"""
內嵌圖示資料模組
自動生成於圖片: q3.ico
"""

import base64
from PyQt5.QtGui import QIcon, QPixmap

# Base64 編碼的圖示資料
Q3_ICON_DATA = """

"""


def get_q3_icon():
    """返回 q3 圖示"""
    pixmap = QPixmap()
    pixmap.loadFromData(base64.b64decode(Q3_ICON_DATA))
    return QIcon(pixmap)


def get_q3_pixmap():
    """返回 q3 像素圖"""
    pixmap = QPixmap()
    pixmap.loadFromData(base64.b64decode(Q3_ICON_DATA))
    return pixmap


